## Implementing a Binary Search Tree in Python
A binary search tree (BST) is a data structure in which each node has at most two children (i.e., left child and right child). Each node represents a value, and the left subtree of a node contains only values less than the node's value, while the right subtree contains only values greater than the node's value. Here's a Python implementation of a BST:

### Code
```python
class Node:
    """Represents a node in the binary search tree."""
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None

class BinarySearchTree:
    """Represents a binary search tree."""
    def __init__(self):
        self.root = None

    def insert(self, value):
        """Inserts a new value into the binary search tree."""
        if not self.root:
            self.root = Node(value)
        else:
            self._insert_recursive(self.root, value)

    def _insert_recursive(self, node, value):
        """Recursively inserts a new value into the binary search tree."""
        if value < node.value:
            if node.left is None:
                node.left = Node(value)
            else:
                self._insert_recursive(node.left, value)
        else:
            if node.right is None:
                node.right = Node(value)
            else:
                self._insert_recursive(node.right, value)

    def search(self, value):
        """Searches for a value in the binary search tree."""
        return self._search_recursive(self.root, value)

    def _search_recursive(self, node, value):
        """Recursively searches for a value in the binary search tree."""
        if node is None:
            return False
        if value == node.value:
            return True
        elif value < node.value:
            return self._search_recursive(node.left, value)
        else:
            return self._search_recursive(node.right, value)

    def delete(self, value):
        """Deletes a value from the binary search tree."""
        self.root = self._delete_recursive(self.root, value)

    def _delete_recursive(self, node, value):
        """Recursively deletes a value from the binary search tree."""
        if node is None:
            return node
        if value < node.value:
            node.left = self._delete_recursive(node.left, value)
        elif value > node.value:
            node.right = self._delete_recursive(node.right, value)
        else:
            if node.left is None:
                return node.right
            elif node.right is None:
                return node.left
            else:
                # Find the minimum value in the right subtree
                min_node = self._find_min(node.right)
                node.value = min_node.value
                node.right = self._delete_recursive(node.right, min_node.value)
        return node

    def _find_min(self, node):
        """Finds the node with the minimum value in the given subtree."""
        while node.left is not None:
            node = node.left
        return node

    def inorder_traversal(self):
        """Performs an inorder traversal of the binary search tree."""
        result = []
        self._inorder_traversal_recursive(self.root, result)
        return result

    def _inorder_traversal_recursive(self, node, result):
        """Recursively performs an inorder traversal of the binary search tree."""
        if node:
            self._inorder_traversal_recursive(node.left, result)
            result.append(node.value)
            self._inorder_traversal_recursive(node.right, result)

# Example usage
bst = BinarySearchTree()
bst.insert(8)
bst.insert(3)
bst.insert(10)
bst.insert(1)
bst.insert(6)
bst.insert(14)
bst.insert(4)
bst.insert(7)
bst.insert(13)

print("Inorder traversal:", bst.inorder_traversal())  # [1, 3, 4, 6, 7, 8, 10, 13, 14]
print("Search for 10:", bst.search(10))  # True
print("Search for 15:", bst.search(15))  # False

bst.delete(10)
print("Inorder traversal after deleting 10:", bst.inorder_traversal())  # [1, 3, 4, 6, 7, 8, 13, 14]
```

### Explanation
The code defines a `Node` class to represent individual nodes in the BST, and a `BinarySearchTree` class to manage the tree. The `BinarySearchTree` class provides methods for inserting, searching, deleting, and traversing the tree.

*   The `insert` method adds a new value to the tree, maintaining the BST property.
*   The `search` method checks if a given value exists in the tree.
